'use client'

import { useEffect, useRef } from 'react'
import { motion, useInView, useMotionValue, animate, useTransform } from 'framer-motion'
import { siteConfig } from '@/lib/config'

// Reusable hook for the animated counter
function useAnimatedCounter(to: number) {
  const count = useMotionValue(0)
  const inViewRef = useRef<HTMLSpanElement>(null)
  const isInView = useInView(inViewRef, { once: true, amount: 0.5 })

  useEffect(() => {
    if (isInView) {
      animate(count, to, {
        duration: 2.2,
        ease: [0.16, 1, 0.3, 1],
      })
    }
  }, [isInView, to, count])

  return { ref: inViewRef, value: count }
}

// Individual Stat Card Component
function StatCard({ value, label }: { value: string; label: string }) {
  // Extract number and suffix (like "%" or "+")
  const numericValue = parseInt(value.match(/\d+/)![0], 10)
  const suffix = value.replace(numericValue.toString(), '').trim()
  
  const counter = useAnimatedCounter(numericValue)
  
  // Transform the raw motion value into a clean integer for rendering
  const rounded = useTransform(counter.value, (latest) => Math.floor(latest))

  return (
    <div className="group relative flex flex-1 flex-col items-center justify-center gap-2 border border-primary/10 bg-cream2 p-8 text-center transition-colors duration-300 hover:bg-stone2">
      {/* Animated background on hover */}
      <div className="absolute inset-x-0 bottom-0 h-full w-full origin-bottom scale-y-0 bg-stone transition-transform duration-300 ease-[cubic-bezier(0.16,1,0.3,1)] group-hover:scale-y-100" />

      {/* Animated Number */}
      <div ref={counter.ref} className="relative font-serif text-5xl font-medium text-primary md:text-6xl">
        <motion.span>{rounded}</motion.span>
        {suffix && <span className="-ml-1 text-3xl font-light text-accent">{suffix}</span>}
      </div>

      {/* Label */}
      <p className="relative font-sans text-xs font-light uppercase tracking-widest text-primary/50">{label}</p>
    </div>
  )
}

// Main Stats Section Component
export default function Stats() {
  const sectionRef = useRef(null)
  const isInView = useInView(sectionRef, { once: true, amount: 0.2 })

  return (
    <section ref={sectionRef} className="border-y border-primary/10 bg-cream">
      <div className="mx-auto max-w-7xl">
        <motion.div 
          initial={{ opacity: 0 }}
          animate={isInView ? { opacity: 1 } : {}}
          transition={{ duration: 1, delay: 0.2 }}
          className="flex flex-col overflow-hidden border-x border-primary/10 md:flex-row"
        >
          {/* Corregido: .items.map para iterar sobre el array correcto */}
          {siteConfig.stats.items.map((stat, index) => (
            <StatCard key={index} value={stat.value} label={stat.label} />
          ))}
        </motion.div>
      </div>
    </section>
  )
}